previewCss:
.darma-loader-darma-custom-107 {
  width: 50px;
  aspect-ratio: 1.154;
  position: relative;
  background: conic-gradient(from 120deg at 50% 64%,#0000, var(--loader-color, #25b09b) 1deg 120deg,#0000 121deg);
  animation: darma-loader-darma-custom-107-l27-0 1.5s infinite cubic-bezier(0.3,1,0,1);
}
.darma-loader-darma-custom-107:before,
.darma-loader-darma-custom-107:after {
  content:'';
  position: absolute;
  inset:0;
  background:inherit;
  transform-origin: 50% 66%;
  animation: darma-loader-darma-custom-107-l27-1 1.5s infinite;
}
.darma-loader-darma-custom-107:after {
  --s:-1;
}
@keyframes darma-loader-darma-custom-107-l27-0 {
   0%,30%      {transform: rotate(0)}
   70%         {transform: rotate(120deg)}
   70.01%,100% {transform: rotate(360deg)}
}
@keyframes darma-loader-darma-custom-107-l27-1 {
   0%      {transform: rotate(calc(var(--s,1)*120deg)) translate(0)}
   30%,70% {transform: rotate(calc(var(--s,1)*120deg)) translate(calc(var(--s,1)*-5px),10px)}
   100%    {transform: rotate(calc(var(--s,1)*120deg)) translate(0)}
}

